import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import com.google.gson.Gson;

class GsonSerializeNullsTest {

  @Test
  void testSerializeNulls_DefaultConstructor() {
    Gson gson = new Gson();
    // Default Gson serializeNulls should be false as per DEFAULT_SERIALIZE_NULLS
    assertFalse(gson.serializeNulls());
  }

  @Test
  void testSerializeNulls_CustomTrue() throws Exception {
    // Using reflection to create Gson instance with serializeNulls = true
    Gson gson = createGsonWithSerializeNulls(true);
    assertTrue(gson.serializeNulls());
  }

  @Test
  void testSerializeNulls_CustomFalse() throws Exception {
    // Using reflection to create Gson instance with serializeNulls = false
    Gson gson = createGsonWithSerializeNulls(false);
    assertFalse(gson.serializeNulls());
  }

  private Gson createGsonWithSerializeNulls(boolean serializeNulls) throws Exception {
    // The public Gson constructor with many args is package-private,
    // so we use reflection to instantiate it and set serializeNulls field.
    Class<Gson> gsonClass = Gson.class;

    // Find the constructor with many parameters
    // Parameters types as per signature:
    // (Excluder, FieldNamingStrategy, Map<Type, InstanceCreator<?>>, boolean serializeNulls,
    // boolean complexMapKeySerialization, boolean generateNonExecutableGson, boolean htmlSafe,
    // boolean prettyPrinting, boolean lenient, boolean serializeSpecialFloatingPointValues,
    // boolean useJdkUnsafe, LongSerializationPolicy, String datePattern, int dateStyle,
    // int timeStyle, List<TypeAdapterFactory>, List<TypeAdapterFactory>, List<TypeAdapterFactory>,
    // ToNumberStrategy, ToNumberStrategy, List<ReflectionAccessFilter>)

    // We can pass null or default values for all except serializeNulls

    java.lang.reflect.Constructor<Gson> constructor = gsonClass.getDeclaredConstructor(
        com.google.gson.internal.Excluder.class,
        com.google.gson.FieldNamingStrategy.class,
        java.util.Map.class,
        boolean.class,
        boolean.class,
        boolean.class,
        boolean.class,
        boolean.class,
        boolean.class,
        boolean.class,
        boolean.class,
        com.google.gson.LongSerializationPolicy.class,
        String.class,
        int.class,
        int.class,
        java.util.List.class,
        java.util.List.class,
        java.util.List.class,
        com.google.gson.ToNumberStrategy.class,
        com.google.gson.ToNumberStrategy.class,
        java.util.List.class
    );
    constructor.setAccessible(true);

    Gson gson = constructor.newInstance(
        null, // Excluder
        null, // FieldNamingStrategy
        null, // Map<Type, InstanceCreator<?>>
        serializeNulls,
        false, // complexMapKeySerialization
        false, // generateNonExecutableGson
        true,  // htmlSafe
        false, // prettyPrinting
        false, // lenient
        false, // serializeSpecialFloatingPointValues
        true,  // useJdkUnsafe
        null,  // LongSerializationPolicy
        null,  // datePattern
        0,     // dateStyle
        0,     // timeStyle
        null,  // builderFactories
        null,  // builderHierarchyFactories
        null,  // factoriesToBeAdded
        null,  // objectToNumberStrategy
        null,  // numberToNumberStrategy
        null   // reflectionFilters
    );
    return gson;
  }
}
